import axios from 'axios';

const API_BASE_URL = process.env.REACT_APP_API_URL || 'http://localhost:5001/api';

// Create axios instance
const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests
apiClient.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('adminToken');
    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }
    return config;
  },
  (error) => {
    return Promise.reject(error);
  }
);

// Handle responses and errors
apiClient.interceptors.response.use(
  (response) => response,
  (error) => {
    if (error.response?.status === 401) {
      localStorage.removeItem('adminToken');
      window.location.href = '/login';
    }
    return Promise.reject(error);
  }
);

// Auth API
export const authAPI = {
  login: (credentials) => apiClient.post('/auth/login', credentials),
  logout: () => apiClient.post('/auth/logout'),
  getSession: () => apiClient.get('/auth/session'),
};

// Users API
export const usersAPI = {
  getUsers: (params) => apiClient.get('/users', { params }),
  getUser: (id) => apiClient.get(`/users/${id}`),
  updateUser: (id, data) => apiClient.put(`/users/${id}`, data),
  deleteUser: (id) => apiClient.delete(`/users/${id}`),
  banUser: (id) => apiClient.post(`/users/${id}/ban`),
  unbanUser: (id) => apiClient.post(`/users/${id}/unban`),
};

// Content API
export const contentAPI = {
  getContent: (params) => apiClient.get('/content', { params }),
  createContent: (data) => apiClient.post('/content', data),
  updateContent: (id, data) => apiClient.put(`/content/${id}`, data),
  deleteContent: (id) => apiClient.delete(`/content/${id}`),
  setFeatured: (id, featured = true) => apiClient.post(`/content/${id}/feature`, { featured }),
  uploadThumbnail: (id, file) => {
    const formData = new FormData();
    formData.append('thumbnail', file);
    return apiClient.post(`/content/${id}/thumbnail`, formData, {
      headers: {
        'Content-Type': 'multipart/form-data',
      },
    });
  },
};

// Analytics API
export const analyticsAPI = {
  getStats: () => apiClient.get('/analytics/stats'),
  getTopContent: (params) => apiClient.get('/analytics/top-content', { params }),
  getActiveUsers: (params) => apiClient.get('/analytics/active-users', { params }),
  getViewsOverTime: (params) => apiClient.get('/analytics/views-over-time', { params }),
};

// Settings API
export const settingsAPI = {
  getProfile: () => apiClient.get('/settings/profile'),
  updateProfile: (data) => apiClient.put('/settings/profile', data),
  changePassword: (data) => apiClient.put('/settings/password', data),
  getNotifications: (params) => apiClient.get('/settings/notifications', { params }),
  markNotificationRead: (id) => apiClient.put(`/settings/notifications/${id}/read`),
  markAllNotificationsRead: () => apiClient.put('/settings/notifications/read-all'),
  deleteNotification: (id) => apiClient.delete(`/settings/notifications/${id}`),
};

export default apiClient;
